const result = $json;
if (!result.results || result.results.length === 0) return [];

return result.results.map(deal => ({
  json: {
    dealId: deal.id,
    dealName: deal.properties.dealname || 'Sem nome',
    contatoNome: deal.properties.contato_nome || '',
    contatoWhatsapp: deal.properties.contato_whatsapp || '',
    segmento: deal.properties.segmento || '',
    pontoDeDor: deal.properties.sdr_ponto_dor || '',
    gancho: deal.properties.sdr_gancho || '',
    canal: deal.properties.canal_outbound || 'WhatsApp',
    website: deal.properties.website || '',
    instagram: deal.properties.instagram_url || ''
  }
}));

const agora = new Date();
const hora = agora.getHours();
const diaSemana = agora.getDay(); // 0=Dom, 6=Sab

const horarioOk = diaSemana >= 1 && diaSemana <= 5 && hora >= 8 && hora < 19;

return [{ json: { ...$json, horarioOk } }];

const d = $json;

const system = `Você é NOVA, representante comercial da Carbon Films — agência de marketing visual cinematográfico em Santa Catarina, Brasil.

Sua tarefa: escrever a mensagem de PRIMEIRO CONTATO via WhatsApp para um prospect. É o primeiro toque — precisa despertar curiosidade genuína, não soar como spam.

REGRAS ABSOLUTAS:
- Inicie obrigatoriamente com [NOVA]:
- Máximo 3 parágrafos curtos (WhatsApp não é e-mail)
- Use o gancho da MIRA como base — não invente outro
- Tom consultivo: você identificou um problema, não está 'vendendo'
- Termine com UMA pergunta aberta
- Nunca mencione preço ou pacotes
- Sem: 'transforme', 'resultados incríveis', 'marketing poderoso'
- Cada palavra deve fazer sentido para ESTA empresa específica
- NÃO use markdown (sem ** ou #)

Responda SOMENTE com o texto da mensagem, pronto para enviar.`;

const user = `Escreva o primeiro contato para:
- Prospect: ${d.contatoNome || d.dealName}
- Empresa: ${d.dealName}
- Segmento: ${d.segmento}
- Gancho MIRA (observação específica desta empresa): ${d.gancho}
- Ponto de dor identificado: ${d.pontoDeDor}
- Canal: WhatsApp`;

return [{
  json: {
    ...d,
    tipoPrompt: 'com_gancho',
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 350,
      system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const d = $json;

const system = `Você é NOVA, representante comercial da Carbon Films — agência de marketing visual cinematográfico em Santa Catarina, Brasil.

Sua tarefa: escrever a mensagem de PRIMEIRO CONTATO via WhatsApp para um prospect. Não há pesquisa específica disponível — use o segmento para criar um gancho relevante.

REGRAS ABSOLUTAS:
- Inicie obrigatoriamente com [NOVA]:
- Máximo 3 parágrafos curtos
- Crie um gancho baseado no segmento (problema comum que empresas desse segmento têm com comunicação visual)
- Tom consultivo: você identificou um padrão, não está 'vendendo'
- Termine com UMA pergunta aberta
- Nunca mencione preço ou pacotes
- Sem: 'transforme', 'resultados incríveis'
- NÃO use markdown

Responda SOMENTE com o texto da mensagem, pronto para enviar.`;

const user = `Escreva o primeiro contato para:
- Prospect: ${d.contatoNome || d.dealName}
- Empresa: ${d.dealName}
- Segmento: ${d.segmento || 'negócio local em SC'}
- Canal: WhatsApp`;

return [{
  json: {
    ...d,
    tipoPrompt: 'sem_gancho',
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 350,
      system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const response = $json;
const prev = $('Gerar Primeiro Contato — Com Gancho').first()?.json || $('Gerar Primeiro Contato — Sem Gancho').first()?.json;

let mensagem = '';
try {
  mensagem = response.content[0].text.trim().replace(/\*\*/g, '').replace(/^#+\s/gm, '');
} catch(e) {
  mensagem = `[NOVA]: Olá, ${prev.contatoNome || prev.dealName}! Estamos trabalhando com marketing visual cinematográfico em SC e vi que a ${prev.dealName} pode se beneficiar do que fazemos. Vale uma conversa rápida?`;
}

// Histórico inicial
const historicoInicial = JSON.stringify([{
  role: 'nova',
  content: mensagem,
  action: 'outbound_inicial',
  estado: 'CONTATO_ENVIADO',
  note: 'Primeiro contato outbound enviado',
  ts: new Date().toISOString()
}]);

return [{
  json: {
    ...prev,
    mensagemGerada: mensagem,
    whatsappBody: JSON.stringify({
      to: prev.contatoWhatsapp,
      type: 'text',
      text: { body: mensagem }
    }),
    hubspotUpdateBody: JSON.stringify({
      properties: {
        sdr_estado: 'CONTATO_ENVIADO',
        sdr_historico: historicoInicial,
        sdr_tentativas: '1',
        sdr_ultimo_contato: String(Date.now()),
        dealstage: $vars.HUBSPOT_STAGE_CONTATO
      }
    }),
    noteBody: JSON.stringify({
      properties: {
        hs_note_body: `[NOVA SDR - D+0] Primeiro contato enviado via WhatsApp.\n\nMensagem:\n${mensagem}`,
        hs_timestamp: String(Date.now())
      },
      associations: [{
        to: { id: prev.dealId },
        types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 214 }]
      }]
    })
  }
}];
